"""Stubs for fairseq.models.hubert.hubert.HubertConfig and HubertModel.

These names are referenced inside the cfg pickle of the fairseq HuBERT
checkpoint. Our checkpoint_utils.load_model_ensemble_and_task does NOT
return instances of these classes — it returns transformers.HubertModel
wrapped in a fairseq-API shim. The classes here exist only so the
unpickler can resolve their names while restoring cfg.

Note: this is the FAIRSEQ HubertModel/HubertConfig (different from the
HuggingFace transformers HubertModel/HubertConfig that we actually use
under the hood)."""


class _Tolerant:
    def __init__(self, *args, **kwargs):
        pass

    def __setstate__(self, state):
        if isinstance(state, dict):
            self.__dict__.update(state)

    def __getattr__(self, name):
        if name.startswith("_"):
            raise AttributeError(name)
        return None

    def __reduce__(self):
        return (self.__class__, ())


class HubertConfig(_Tolerant):
    pass


class HubertModel(_Tolerant):
    pass
